import {
  addDoc,
  collection,
  deleteDoc,
  doc,
  getDoc,
  getDocs,
  getFirestore,
  limit,
  onSnapshot,
  orderBy,
  query,
  runTransaction,
  setDoc,
  updateDoc,
  where
} from 'firebase/firestore';
import AsyncStorage from '@react-native-async-storage/async-storage';
import {
  createUserWithEmailAndPassword,
  onAuthStateChanged,
  signInWithEmailAndPassword,
  signOut
} from 'firebase/auth';
import { Platform } from 'react-native';
import { auth, db, firebaseConfig } from '../firebaseConfig';
const PHONE_LOGIN_PASSWORD = 'PhoneLogin#1';
const USER_PROFILE_CACHE_PREFIX = 'userProfile:';

const normalizePhone = (phone: string) => phone.replace(/[^0-9+]/g, '');
const isPhoneLoginCredentialError = (code?: string) =>
  code === 'auth/user-not-found' || code === 'auth/invalid-credential' || code === 'auth/invalid-login-credentials';

const phoneToEmail = (phone: string) => {
  const normalized = normalizePhone(phone).replace(/^\+/, '');
  return `${normalized}@phone.local`;
};

export type OrderStatus =
  | 'pending'
  | 'confirmed'
  | 'preparing'
  | 'out_for_delivery'
  | 'delivered'
  | 'cancelled';

export type PaymentStatus = 'unpaid' | 'partial' | 'paid' | 'pending';

export type DeliverySlot = 'Morning' | 'Afternoon' | 'Evening' | 'Express delivery';

export type OrderRecord = {
  id?: string;
  orderNumber?: number;
  customerId: string;
  ownerId?: string;
  customerName: string;
  phone?: string;
  address?: string;
  productName: string;
  quantity: number;
  pricePerCan: number;
  deliveryCharge: number;
  totalAmount: number;
  availableStock?: number;
  note?: string;
  paymentMethod: string;
  paymentStatus: PaymentStatus;
  paidAmount?: number;
  deliverySlot: DeliverySlot;
  expectedDeliveryTime?: string;
  subscription?: boolean;
  status: OrderStatus;
  createdAt: number;
  updatedAt: number;
};

export type UserProfileData = {
  uid: string;
  name: string;
  email: string;
  phone: string;
  address?: string;
  role: 'customer' | 'owner';
  approved: boolean;
};

export type InventorySummary = {
  openingStock: number;
  restockedCans: number;
  soldCans: number;
  purchasePrice: number;
  sellPrice: number;
};

export type InventoryActivity = {
  id?: string;
  type: 'restock' | 'order';
  quantity: number;
  createdAt: number;
  orderId?: string;
  orderNumber?: number;
  customerName?: string;
};

type CreateOrderInput = Omit<OrderRecord, 'id' | 'createdAt' | 'updatedAt' | 'status'>;
type UpdateOrderInput = Partial<
  Omit<OrderRecord, 'id' | 'createdAt' | 'updatedAt' | 'orderNumber' | 'status'>
>;

const getUserProfileCacheKey = (uid: string) => `${USER_PROFILE_CACHE_PREFIX}${uid}`;

const cacheUserProfile = async (profile: UserProfileData) => {
  await AsyncStorage.setItem(getUserProfileCacheKey(profile.uid), JSON.stringify(profile));
};

const getCachedUserProfile = async (uid: string): Promise<UserProfileData | null> => {
  const cached = await AsyncStorage.getItem(getUserProfileCacheKey(uid));
  if (!cached) {
    return null;
  }

  try {
    return JSON.parse(cached) as UserProfileData;
  } catch {
    return null;
  }
};

const parseFirestoreString = (value?: { stringValue?: string }) => value?.stringValue ?? '';
const parseFirestoreBoolean = (value?: { booleanValue?: boolean }) => value?.booleanValue ?? false;

const fetchUserProfileViaRest = async (uid: string): Promise<UserProfileData | null> => {
  const user = auth.currentUser;
  if (!user) {
    return null;
  }

  const token = await user.getIdToken();
  const response = await fetch(
    `https://firestore.googleapis.com/v1/projects/${firebaseConfig.projectId}/databases/(default)/documents/users/${uid}`,
    {
      headers: {
        Authorization: `Bearer ${token}`
      }
    }
  );

  if (response.status === 404) {
    return null;
  }

  if (!response.ok) {
    throw new Error(`Profile request failed with status ${response.status}`);
  }

  const payload = (await response.json()) as {
    fields?: {
      uid?: { stringValue?: string };
      name?: { stringValue?: string };
      email?: { stringValue?: string };
      phone?: { stringValue?: string };
      address?: { stringValue?: string };
      role?: { stringValue?: 'customer' | 'owner' };
      approved?: { booleanValue?: boolean };
    };
  };

  const fields = payload.fields;
  if (!fields) {
    return null;
  }

  return {
    uid: parseFirestoreString(fields.uid) || uid,
    name: parseFirestoreString(fields.name),
    email: parseFirestoreString(fields.email),
    phone: parseFirestoreString(fields.phone),
    address: parseFirestoreString(fields.address),
    role: fields.role?.stringValue === 'owner' ? 'owner' : 'customer',
    approved: parseFirestoreBoolean(fields.approved)
  };
};

const normalizeStatus = (status: string | undefined): OrderStatus => {
  switch (status) {
    case 'confirmed':
      return 'confirmed';
    case 'preparing':
      return 'preparing';
    case 'out_for_delivery':
    case 'dispatched':
      return 'out_for_delivery';
    case 'delivered':
      return 'delivered';
    case 'cancelled':
      return 'cancelled';
    default:
      return 'pending';
  }
};

const normalizeOrderRecord = (id: string, data: Partial<OrderRecord>): OrderRecord => {
  const quantity = data.quantity ?? 0;
  const pricePerCan = data.pricePerCan ?? 20;
  const deliveryCharge = data.deliveryCharge ?? 0;
  const paidAmount = data.paidAmount ?? 0;
  const paymentMethod = data.paymentMethod ?? 'Cash on Delivery';
  const paymentStatus =
    data.paymentStatus ??
    (paymentMethod === 'Cash on Delivery' ? 'unpaid' : paidAmount > 0 ? 'paid' : 'pending');
  const totalAmount = data.totalAmount ?? quantity * pricePerCan + deliveryCharge;

  return {
    id,
    orderNumber: data.orderNumber ?? 0,
    customerId: data.customerId ?? '',
    ownerId: data.ownerId,
    customerName: data.customerName ?? 'Customer',
    phone: data.phone ?? '',
    address: data.address ?? '',
    productName: data.productName ?? '20L Drinking Water Can',
    quantity,
    pricePerCan,
    deliveryCharge,
    totalAmount,
    availableStock: data.availableStock ?? 0,
    note: data.note ?? '',
    paymentMethod,
    paymentStatus,
    paidAmount,
    deliverySlot: data.deliverySlot ?? 'Morning',
    expectedDeliveryTime: data.expectedDeliveryTime ?? 'Today, 30-45 min',
    subscription: data.subscription ?? false,
    status: normalizeStatus(data.status),
    createdAt: data.createdAt ?? Date.now(),
    updatedAt: data.updatedAt ?? data.createdAt ?? Date.now()
  };
};

